firmware_template.source:
#include "ws_client.h"
static WebSocketsClient ws;
static ws_msg_cb _cb=nullptr;
void _ws_event(WStype_t t,uint8_t*p,size_t l){
  if(t==WStype_TEXT&&_cb)_cb((char*)p);
  if(t==WStype_CONNECTED)Serial.println("[ws] Connected");
  if(t==WStype_DISCONNECTED)Serial.println("[ws] Disconnected");
}
void ws_setup(const char*h,uint16_t p,const char*path){ws.begin(h,p,path);ws.onEvent(_ws_event);Serial.println("[ws] OK");}
void ws_loop(){ws.loop();}
void ws_send(const char*msg){ws.sendTXT(msg);}
void ws_on_message(ws_msg_cb cb){_cb=cb;}
